169:     public int getCreateConsumerBackoffMaxAttempts() {
170:         return createConsumerBackoffMaxAttempts;
171:     }
172: 
173:     /**
174:      * Maximum attempts to create the kafka consumer (kafka-client), before eventually giving up and failing.
175:      *
176:      * Error during creating the consumer may be fatal due to invalid configuration and as such recovery is not
177:      * possible. However, one part of the validation is DNS resolution of the bootstrap broker hostnames. This may be a
178:      * temporary networking problem, and could potentially be recoverable. While other errors are fatal, such as some
179:      * invalid kafka configurations. Unfortunately, kafka-client does not separate this kind of errors.
180:      *
181:      * Camel will by default retry forever, and therefore never give up. If you want to give up after many attempts then
182:      * set this option and Camel will then when giving up terminate the consumer. To try again, you can manually restart
183:      * the consumer by stopping, and starting the route.
184:      */
185:     public void setCreateConsumerBackoffMaxAttempts(int createConsumerBackoffMaxAttempts) {
186:         this.createConsumerBackoffMaxAttempts = createConsumerBackoffMaxAttempts;
187:     }
188: 
189:     public long getCreateConsumerBackoffInterval() {
190:         return createConsumerBackoffInterval;
191:     }
192: 
193:     /**
194:      * The delay in millis seconds to wait before trying again to create the kafka consumer (kafka-client).
195:      */
196:     public void setCreateConsumerBackoffInterval(long createConsumerBackoffInterval) {
197:         this.createConsumerBackoffInterval = createConsumerBackoffInterval;
198:     }
