200:     public int getSubscribeConsumerBackoffMaxAttempts() {
201:         return subscribeConsumerBackoffMaxAttempts;
202:     }
203: 
204:     /**
205:      * Maximum number the kafka consumer will attempt to subscribe to the kafka broker, before eventually giving up and
206:      * failing.
207:      *
208:      * Error during subscribing the consumer to the kafka topic could be temporary errors due to network issues, and
209:      * could potentially be recoverable.
210:      *
211:      * Camel will by default retry forever, and therefore never give up. If you want to give up after many attempts,
212:      * then set this option and Camel will then when giving up terminate the consumer. You can manually restart the
213:      * consumer by stopping and starting the route, to try again.
214:      */
215:     public void setSubscribeConsumerBackoffMaxAttempts(int subscribeConsumerBackoffMaxAttempts) {
216:         this.subscribeConsumerBackoffMaxAttempts = subscribeConsumerBackoffMaxAttempts;
217:     }
218: 
219:     public long getSubscribeConsumerBackoffInterval() {
220:         return subscribeConsumerBackoffInterval;
221:     }
222: 
223:     /**
224:      * The delay in millis seconds to wait before trying again to subscribe to the kafka broker.
225:      */
226:     public void setSubscribeConsumerBackoffInterval(long subscribeConsumerBackoffInterval) {
227:         this.subscribeConsumerBackoffInterval = subscribeConsumerBackoffInterval;
228:     }
