230:     public boolean isSubscribeConsumerTopicMustExists() {
231:         return subscribeConsumerTopicMustExists;
232:     }
233: 
234:     /**
235:      * Whether when a Camel Kafka consumer is subscribing to a Kafka broker then check whether a topic already exist on
236:      * the broker, and fail if it does not. Otherwise, the Camel Kafka consumer will keep attempt to consume from the
237:      * topic, until it's created on the Kafka broker; and until then the Camel Kafka consumer will fail and log a WARN
238:      * about UNKNOWN_TOPIC_OR_PARTITION.
239:      *
240:      * The option subscribeConsumerBackoffMaxAttempts can be configured to give up trying to subscribe after a given
241:      * number of attempts.
242:      */
243:     public void setSubscribeConsumerTopicMustExists(boolean subscribeConsumerTopicMustExists) {
244:         this.subscribeConsumerTopicMustExists = subscribeConsumerTopicMustExists;
245:     }
