247:     @Override
248:     protected void doInit() throws Exception {
249:         super.doInit();
250: 
251:         // if a factory was not autowired then create a default factory
252:         if (kafkaClientFactory == null) {
253:             kafkaClientFactory = new DefaultKafkaClientFactory();
254:         }
255:         if (configuration.isAllowManualCommit() && kafkaManualCommitFactory == null) {
256:             LOG.warn("The component was setup for allowing manual commits, but a manual commit factory was not set");
257:         }
258:     }
259: 
260:     @Override
261:     protected void doStart() throws Exception {
262:         super.doStart();
263: 
264:         Map<String, Object> map = new HashMap<>();
265:         // resolve parameter values from the values (#bean / #class etc)
266:         PropertyBindingSupport.bindProperties(getCamelContext(), map, configuration.getAdditionalProperties());
267:         configuration.setAdditionalProperties(map);
268:     }
269: }
