17: package org.apache.camel.component.direct;
18: 
19: import java.util.HashMap;
20: import java.util.Map;
21: import java.util.concurrent.TimeUnit;
22: import java.util.concurrent.locks.Condition;
23: import java.util.concurrent.locks.Lock;
24: import java.util.concurrent.locks.ReentrantLock;
25: 
26: import org.apache.camel.Endpoint;
27: import org.apache.camel.spi.Metadata;
28: import org.apache.camel.spi.annotations.Component;
29: import org.apache.camel.support.DefaultComponent;
