162:     <T> Class<T> loadClass(Object o, ClassResolver resolver, Class<T> type) {
163:         if (o == null || o instanceof Class) {
164:             return CastUtils.cast((Class<?>) o);
165:         }
166:         String name = o.toString();
167:         Class<T> c = resolver.resolveClass(name, type);
168:         if (c == null) {
169:             c = resolver.resolveClass(name, type, getClass().getClassLoader());
170:         }
171:         if (c == null) {
172:             c = resolver.resolveClass(name, type, org.apache.kafka.clients.producer.KafkaProducer.class.getClassLoader());
173:         }
174:         return c;
175:     }
